+                    }
+                }
+                None
+            }
+            AppAction::Help => self.handle_slash_command(SlashCommand::Help, ""),
+            AppAction::OpenSettings => self.handle_slash_command(SlashCommand::Settings, ""),
+
+            // =========================================================
+            // Models & thinking
+            // =========================================================
+            AppAction::CycleModelForward => {
+                self.cycle_model(1);
+                None
+            }
+            AppAction::CycleModelBackward => {
+                self.cycle_model(-1);
