+/// Standard CLI args for interactive mode with minimal features (no API calls).
+fn minimal_interactive_args() -> Vec<&'static str> {
+    vec![
+        "--provider",
+        "openai",
+        "--model",
+        "gpt-4o-mini",
+        "--no-tools",
+        "--no-skills",
+        "--no-prompt-templates",
