+        assert_eq!(resp_a["id"], "a");
+        assert_eq!(resp_b["id"], "b");
+        assert_eq!(resp_c["id"], "c");
+        assert_eq!(resp_a["success"], true);
+        assert_eq!(resp_b["success"], true);
+        assert_eq!(resp_c["success"], true);
+    });
+}
